import React, { useState } from 'react';
import axios from 'axios';
import './MemberForm.css';

function MemberForm({ onSuccess }) {
  const [formData, setFormData] = useState({
    member_number: '',
    name: '',
    phone: '',
    aadhaar: '',
    address: '',
    chit_amount: '',
    start_date: '',
    due_date: ''
  });
  const [photo, setPhoto] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const data = new FormData();
    Object.keys(formData).forEach(key => data.append(key, formData[key]));
    if (photo) data.append('photo', photo);

    try {
      await axios.post('/api/members', data);
      onSuccess();
    } catch (err) {
      alert('Error creating member');
    }
  };

  return (
    <div className="form-container">
      <form onSubmit={handleSubmit} className="member-form">
        <h2>Add New Member</h2>
        <input
          type="text"
          placeholder="Member Number"
          value={formData.member_number}
          onChange={(e) => setFormData({...formData, member_number: e.target.value})}
          required
        />
        <input
          type="text"
          placeholder="Name"
          value={formData.name}
          onChange={(e) => setFormData({...formData, name: e.target.value})}
          required
        />
        <input
          type="text"
          placeholder="Phone"
          value={formData.phone}
          onChange={(e) => setFormData({...formData, phone: e.target.value})}
        />
        <input
          type="text"
          placeholder="Aadhaar Number"
          value={formData.aadhaar}
          onChange={(e) => setFormData({...formData, aadhaar: e.target.value})}
        />
        <textarea
          placeholder="Address"
          value={formData.address}
          onChange={(e) => setFormData({...formData, address: e.target.value})}
        />
        <input
          type="number"
          placeholder="Chit Amount"
          value={formData.chit_amount}
          onChange={(e) => setFormData({...formData, chit_amount: e.target.value})}
          required
        />
        <input
          type="date"
          placeholder="Start Date"
          value={formData.start_date}
          onChange={(e) => setFormData({...formData, start_date: e.target.value})}
          required
        />
        <input
          type="date"
          placeholder="Due Date"
          value={formData.due_date}
          onChange={(e) => setFormData({...formData, due_date: e.target.value})}
          required
        />
        <input
          type="file"
          accept="image/*"
          onChange={(e) => setPhoto(e.target.files[0])}
        />
        <button type="submit" className="btn-primary">Create Member</button>
      </form>
    </div>
  );
}

export default MemberForm;
